            local ONCAL="" ONBOOT=""
            case "$IV" in
                1) ONCAL="*:0/15" ;; 2) ONCAL="hourly" ;; 3) ONCAL="daily" ;;
                4) ONBOOT="120" ;; 5) read -p "OnCalendar= " ONCAL ;;
            esac
            read -p "Command to execute: " CMD
