ExecStart=/bin/bash ${KNOCK_DIR}/spa_listener.sh
Restart=always
[Install]
WantedBy=multi-user.target
SVEOF
            systemctl daemon-reload && systemctl enable --now d3m0n-spa.service 2>/dev/null
